  if (!projects[projectId]) {
    projects[projectId] = {};
  }

  if (!projects[projectId][taskId]) {
    projects[projectId][taskId] = [];
  }

  const newComment = { id: randomUUID(), ...comment };
  projects[projectId][taskId].push(newComment);
  return newComment;
}

